import cv2from matplotlib import pyplot as pltimport numpy as npimg = cv2.imread("../data/Alloy.jpg",0)equalized = cv2.equalizeHist(img)"""Histogram equalization improves image contrast by redistributing pixel intensitiesspreads intensity values across a wider rangeso that dark and bright regions become more distinguishable"""plt.figure(figsize=(6,4))plt.hist(img.flat, bins=100, range=(0,255))plt.title("Original Histogram")plt.figure(figsize=(6,4))plt.hist(equalized.flat, bins=100, range=(0,255))plt.title("Equalized Histogram")plt.figure(figsize=(8,4))plt.subplot(1,2,1)plt.imshow(img, cmap='gray')plt.title("Original")plt.subplot(1,2,2)plt.imshow(equalized, cmap='gray')plt.title("Equalized")plt.show()clahe = cv2.createCLAHE(clipLimit = 2.0, tileGridSize = (8,8))#Contrast Limited Adaptive Histogram Equalization"""CLAHE divides the image into small tilesEach tile is equalized independentlyclipLimit = 2.0 controls maximum contrast amplificationtileGridSize = (8,8)Controls how many local regions are createdSmall tiles:stronger local enhancementmore sensitive to noiseLarge tiles:closer to global equalizationsmoother appearance"""cl_img = clahe.apply(img)plt.subplot(1,2,1)plt.imshow(cl_img, cmap='gray')plt.title("CLAHE")plt.show()plt.figure(figsize=(6,4))plt.hist(cl_img.flat, bins=100, range=(100,255))plt.title("CLAHE Histogram")ret, thresh1 = cv2.threshold(cl_img, 190, 150, cv2.THRESH_BINARY)ret, thresh2 = cv2.threshold(cl_img, 190, 255, cv2.THRESH_BINARY_INV+cv2.THRESH_OTSU)"""if pixel intensity > threshold: assign one value else: assign another valueret = 190if thresh otsu, ret will be importantthresh1 is a map of 150 and 0"""plt.figure(figsize=(8,4))plt.subplot(1,2,1)plt.imshow(thresh1, cmap='gray')plt.title("Binary Threshold1")plt.subplot(1,2,2)plt.imshow(thresh2, cmap='gray')plt.title("Binary Threshold2")plt.show()